mapper.select:
SELECT * FROM attempts
WHERE user_id=#{userId} AND level_id=#{levelId}
ORDER BY created_at DESC
LIMIT #{n}


SELECT a2.user_id AS userId, COUNT(DISTINCT a2.question_id) AS overlap
FROM attempts a1
JOIN attempts a2 ON a1.question_id = a2.question_id
WHERE a1.user_id=#{userId}
  AND a2.user_id <> #{userId}
GROUP BY a2.user_id
ORDER BY overlap DESC
LIMIT #{limit}


SELECT DISTINCT a.user_id AS userId, a.question_id AS questionId
FROM attempts a
WHERE a.is_correct=1
  AND a.user_id IN
  #{uid}

  AND a.question_id NOT IN
  #{qid}

ORDER BY a.user_id ASC, a.question_id ASC
LIMIT #{limit}
